const [index, setIndex] = useState(testimonials.length)

useEffect(() => {
  if (paused) return
  const timer = window.setInterval(() => setIndex(i => i + 1), 3000)
  return () => window.clearInterval(timer)
}, [paused])

// On transitionEnd, recenter cloned boundary without animation.`,validations:[`Interval clears on pause and unmount`,`Clone boundary recenters without a visible jump`,`Controls have accessible labels`,`Reduced motion disables auto-advance`]},{id:`studio-mouse-trail`,preset:`studio`,group:`Interactive Systems`,number:`09`,title:`Partner Mouse Trail`,category:`Pointer`,kind:`studio-mouse-trail`,summary:`Spawn short-lived project thumbnails behind a centered partnership CTA as the pointer moves.`,prompt:`Build a large PartnerSection with centered serif heading and CTA. For fine pointers, spawn a project GIF at the cursor no more than once every 80ms. Give each thumbnail a random rotation from -10 to 10 degrees, animate opacity and scale to zero over one second, then remove it. Cap the active trail count, ignore coarse pointers, and cancel timers or animation frames on unmount.`,script:`function spawnTrail(x, y) {
